+        // Mesh repair is reversible, so auto-applied.
+        let mesh_actions: Vec<_> = result
+            .actions
+            .iter()
+            .filter(|a| a.component == SetupComponent::Mesh)
+            .collect();
+        assert!(mesh_actions.iter().all(|a| a.applied));
